const query = $json.body.query || '';
const id = $json.body.id || '';
const mode = ($json.body.mode || 'OR').toUpperCase();
const userId = $json.body.user_id || 'tester';
const customerId = $json.body.customer_id || ''; // ✅ 추가: 고객 ID 입력값

let finalQuery = {};
let isIdSearch = false; // ID 검색 여부를 판단하는 플래그

// 1. ID가 존재하는 경우
if (id) {
  // ID 검색 쿼리 객체 생성
  // MongoDB Extended JSON 형식의 "$oid"를 사용
  finalQuery = {
    $and: [
      { ownerId: userId },
      { _id: { "$oid": id } },
      ...(customerId ? [{ customerId: { "$oid": customerId } }] : []) // ✅ customerId 필드 사용
    ]
  };
  isIdSearch = true;
} 
// 2. ID가 없고 키워드가 존재하는 경우 (기존 로직)
else if (query.trim().length > 0) {
  const keywords = query
    .split(' ')
    .map(k => k.trim())
    .filter(k => k.length > 0);

  const fields = [
    'upload.originalName',
    'ocr.full_text',
    'ocr.summary',
    'ocr.tags',
    'meta.filename',
    'meta.full_text',
    'meta.summary',
    'meta.tags',
    'text.full_text',
    'customer_relation.notes'
  ];

  const buildSingleKeywordQuery = (keyword) =>
    fields.map(field => ({ [field]: { $regex: keyword, $options: 'i' } }));

  if (mode === 'AND') {
    finalQuery = {
      $and: [
        { ownerId: userId },
        ...(customerId ? [{ customerId: { "$oid": customerId } }] : []), // ✅ customerId 필드 사용
        ...keywords.map(kw => ({ $or: buildSingleKeywordQuery(kw) }))
      ]
    };
  } else {
    finalQuery = {
      $and: [
        { ownerId: userId },
        ...(customerId ? [{ customerId: { "$oid": customerId } }] : []), // ✅ customerId 필드 사용
        { $or: keywords.flatMap(kw => buildSingleKeywordQuery(kw)) }
      ]
    };
  }
}
// 3. ID도 없고 키워드도 없는 경우
else {
  return [{ json: {} }];
}


// 다음 노드로 쿼리와 플래그를 함께 전달
return [{
  json: {
    query: finalQuery,
    isIdSearch: isIdSearch
  }
}];

// Stringify Mongo Query 노드 - ObjectId 변환 포함 최종 버전
const input = $json;
const mongoQuery = input.query;
const isIdSearch = input.isIdSearch;

let outputJson;

// 1️⃣ ID 검색일 경우
if (isIdSearch) {
  outputJson = {
    _id: mongoQuery._id["$oid"] || mongoQuery._id
  };
}
// 2️⃣ 키워드 검색일 경우
else {
  outputJson = mongoQuery;
}

// 3️⃣ "$oid" 제거 (ObjectId → 순수 문자열)
function cleanOid(obj) {
  if (Array.isArray(obj)) return obj.map(cleanOid);
  if (obj && typeof obj === "object") {
    const newObj = {};
    for (const [key, value] of Object.entries(obj)) {
      if (key === "$oid") return value;
      newObj[key] = cleanOid(value);
    }
    return newObj;
  }
  return obj;
}
const cleaned = cleanOid(outputJson);

// 4️⃣ ObjectId 변환 로직 주입 (customerId 필드 사용)
if (cleaned.$and) {
  cleaned.$and = cleaned.$and.map(cond => {
    if (cond.customerId) {
      return {
        $expr: {
          $eq: [
            "$customerId",
            { $toObjectId: cond.customerId }
          ]
        }
      };
    }
    return cond;
  });
}

// 5️⃣ JSON 문자열로 변환
const jsonStr = JSON.stringify(cleaned);

// 6️⃣ 결과 반환
return [
  {
    json: {
      mongoQuery: jsonStr
    }
  }
];
